Here's my configuration for the reference. It's super simple and there's nothing in it that is related to eap-radius.

connections {
        ikev2 {
                version = 2
                encap = yes
                dpd_delay = 30s
                keyingtries = 0
                send_certreq = no
                send_cert = always
                pools = ipv4, ipv6
                proposals = aes256-sha256-ecp256,aes256-sha384-modp2048
                local {
                        auth = pubkey
                        certs = server.crt
                        id = <host fqdn here>
                }
                remote {
                        auth = eap-tls
                        cacerts = ca.crt
                        eap_id = %any
                }
                children {
                        default {
                                esp_proposals = aes256-sha256,aes256gcm16
                                local_ts = 0.0.0.0/0, ::/0
                                hw_offload = auto
                        }
                }
        }
}

I'll try to open the bug upstream per your suggestion.
